import React from "react";

const get = (obj, path, fallback = "") =>
  path.split(".").reduce((o, k) => (o && o[k] != null ? o[k] : null), obj) ?? fallback;

export default function WeatherNow({ data = {} }) {
  const tempC = get(data, "temp", null);
  const feels = get(data, "feels_like", null);
  const desc  = get(data, "weather.0.description", "—");
  const wind  = get(data, "wind_speed", null);
  const hum   = get(data, "humidity", null);

  return (
    <div className="rounded-2xl bg-white/20 backdrop-blur border border-white/20 px-4 py-4 shadow-sm">
      <div className="flex items-end gap-3">
        <div className="text-4xl font-semibold">{tempC != null ? Math.round(tempC) : "—"}°</div>
        <div className="text-sm opacity-80">Feels like {feels != null ? Math.round(feels) : "—"}°</div>
      </div>
      <div className="capitalize mt-1 opacity-80">{desc}</div>
      <div className="mt-3 text-sm opacity-80 flex gap-4">
        <div>💨 {wind != null ? Math.round(wind) : "—"} m/s</div>
        <div>💧 {hum != null ? hum : "—"}%</div>
      </div>
    </div>
  );
}
